function chunkText(text, max = DEFAULT_MAX) {
  if (text.length === 0) {
    return [];
  }
  if (text.length <= max) {
    return [text];
  }
  const chunks = [];
  let cursor = 0;
  while (cursor < text.length) {
    const remaining = text.length - cursor;
    if (remaining <= max) {
      chunks.push(text.slice(cursor));
      break;
    }
    let cut = cursor + max;
    const searchStart = Math.max(cursor, cut - WHITESPACE_LOOKBACK);
    const window2 = text.slice(searchStart, cut);
    const wsIdx = window2.search(/\s\S*$/);
    if (wsIdx > 0) {
      cut = searchStart + wsIdx;
    }
    chunks.push(text.slice(cursor, cut));
    cursor = cut;
    while (cursor < text.length && /\s/.test(text[cursor])) {
      cursor++;
    }
  }
  return chunks;
}

