function parsePayloadVerdict(payload) {
  if (!payload) {
    return null;
  }
  let parsed;
  try {
    parsed = JSON.parse(payload);
  } catch {
    return null;
  }
  if (typeof parsed !== "object" || parsed === null) {
    return null;
  }
  const obj = parsed;
  if (obj.a !== "verdict") {
    return null;
  }
  if (typeof obj.r !== "string" || obj.r.length === 0) {
    return null;
  }
  if (obj.b !== "allow" && obj.b !== "deny") {
    return null;
  }
  return { behavior: obj.b, request_id: obj.r };
}

